import React, { useState, useEffect, useContext } from "react";
import { useParams, useNavigate } from "react-router-dom";
import AuthContext from "../context/AuthContext";
import axios from 'axios';
import "./CAProfile.css";

function CAProfile() {
    const { id } = useParams();
    const navigate = useNavigate();
    const { user } = useContext(AuthContext);
    const [ca, setCa] = useState(null);
    const [loading, setLoading] = useState(true);
    const [activeTab, setActiveTab] = useState('about');

    useEffect(() => {
        fetchCA();
    }, [id]);

    const fetchCA = async () => {
        try {
            const response = await axios.get(`http://localhost:5001/api/ca/${id}`);
            setCa(response.data);
        } catch (error) {
            console.error("Error fetching CA:", error);
        } finally {
            setLoading(false);
        }
    };

    const handleChat = () => {
        if (!user) {
            alert("Please login to chat with this CA");
            navigate("/login");
            return;
        }
        if (!user.isSubscribed && user.role === "user") {
            navigate('/subscription');
            return;
        }
        if (!ca.userId) return;
        navigate(`/chat/${ca.userId}`, { state: { caName: ca.name } });
    };

    if (loading) return <div className="container animate-fade">Loading profile...</div>;
    if (!ca) return <div className="container">CA not found</div>;

    return (
        <div className="ca-profile-modern">
            <div className="profile-hero">
                <div className="hero-bg" style={{ backgroundImage: `url(${ca.headerImage || 'https://images.unsplash.com/photo-1554224155-6726b3ff858f?auto=format&fit=crop&q=80&w=1200'})` }}>
                    <div className="hero-overlay"></div>
                </div>
                <div className="container hero-content animate-up">
                    <button className="back-btn-float" onClick={() => navigate(-1)}>
                        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M19 12H5M12 19l-7-7 7-7"/></svg>
                    </button>
                    <div className="profile-card-top card">
                        <div className="profile-identity">
                            <div className="profile-avatar-wrapper">
                                <div className="profile-avatar-main">
                                    {ca.name.charAt(0)}
                                </div>
                                <div className="verified-badge">✓</div>
                            </div>
                            <div className="profile-main-info">
                                <h1>{ca.name}</h1>
                                <p className="spec-tag">{ca.specialization}</p>
                                <div className="profile-tags">
                                    <span>📍 {ca.location}</span>
                                    <span>💼 {ca.experience} Experience</span>
                                </div>
                            </div>
                        </div>
                        <div className="profile-stats">
                            <div className="stat-box">
                                <strong>{ca.rating}</strong>
                                <span>Rating</span>
                            </div>
                            <div className="stat-box">
                                <strong>{ca.subscribersCount || '1.2k'}</strong>
                                <span>Subscribers</span>
                            </div>
                            <div className="stat-box">
                                <strong>{ca.reviews?.length || 0}</strong>
                                <span>Reviews</span>
                            </div>
                        </div>
                        <div className="profile-primary-actions">
                            <button className="btn btn-primary" onClick={handleChat}>Message Now</button>
                            <button className="btn btn-outline" onClick={() => navigate('/subscription')}>Subscribe</button>
                        </div>
                    </div>
                </div>
            </div>

            <main className="container profile-body animate-up delay-1">
                <div className="profile-tabs">
                    <button className={activeTab === 'about' ? 'active' : ''} onClick={() => setActiveTab('about')}>About</button>
                    <button className={activeTab === 'services' ? 'active' : ''} onClick={() => setActiveTab('services')}>Services</button>
                    <button className={activeTab === 'reviews' ? 'active' : ''} onClick={() => setActiveTab('reviews')}>Reviews</button>
                </div>

                <div className="tab-content card">
                    {activeTab === 'about' && (
                        <div className="about-tab animate-fade">
                            <h2>About the Professional</h2>
                            <p>{ca.about}</p>
                            <div className="expertise-grid">
                                <div className="expertise-item">
                                    <h4>Taxation</h4>
                                    <p>Comprehensive GST and Income Tax solutions.</p>
                                </div>
                                <div className="expertise-item">
                                    <h4>Audit</h4>
                                    <p>Statutory and Internal audit expertise.</p>
                                </div>
                            </div>
                        </div>
                    )}

                    {activeTab === 'services' && (
                        <div className="services-tab animate-fade">
                            <h2>Professional Services</h2>
                            <div className="service-list">
                                <div className="service-item">
                                    <div className="service-info">
                                        <h4>GST Filing</h4>
                                        <p>Monthly & Annual GST compliance.</p>
                                    </div>
                                    <span className="price">₹1,500</span>
                                </div>
                                <div className="service-item">
                                    <div className="service-info">
                                        <h4>Tax Audit</h4>
                                        <p>Financial verification and reporting.</p>
                                    </div>
                                    <span className="price">₹5,000</span>
                                </div>
                            </div>
                        </div>
                    )}

                    {activeTab === 'reviews' && (
                        <div className="reviews-tab animate-fade">
                            <h2>Client Feedback</h2>
                            <div className="reviews-list-modern">
                                {ca.reviews && ca.reviews.length > 0 ? (
                                    ca.reviews.map((r, i) => (
                                        <div key={i} className="review-card-modern">
                                            <div className="review-user">
                                                <div className="user-initial">{r.userName.charAt(0)}</div>
                                                <div>
                                                    <strong>{r.userName}</strong>
                                                    <div className="stars">{"★".repeat(r.rating)}</div>
                                                </div>
                                            </div>
                                            <p>{r.comment}</p>
                                        </div>
                                    ))
                                ) : (
                                    <p className="empty-state">No reviews yet. Be the first to review!</p>
                                )}
                            </div>
                        </div>
                    )}
                </div>
            </main>
        </div>
    );
}

export default CAProfile;
